  await new Promise((resolve) => setTimeout(resolve, 1500));

  products = products.map((product, index) => {
    const inventory = Math.max(0, product.inventory + randomDelta(-8, 12));
    const availability = inventory === 0 ? 'Out of stock' : inventory < 10 ? 'Limited stock' : 'In stock';

    return {
      ...product,
      price: product.price + randomDelta(-25, 40),
      inventory,
      availability,
      syncedAt: new Date(Date.now() + index).toISOString()
    };
  });
}
"}

