{"path":"/home/user/workspace/app/page.tsx","content":"import { revalidateTag, updateTag } from 'next/cache';
import { getAllProducts, syncLatestCatalog } from '../lib/db';

async function syncCatalogAction() {
  'use server';

  void (async () => {
    await syncLatestCatalog();
    revalidateTag('products', 'max');
  })();

  updateTag('products');
}

export default async function Page() {
  const products = await getAllProducts();

  return (
    <main style={{ padding: '2rem', fontFamily: 'Arial, sans-serif' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem', gap: '1rem', flexWrap: 'wrap' }}>
        <div>
          <p style={{ margin: 0, color: '#666', fontSize: '0.875rem', textTransform: 'uppercase', letterSpacing: '0.08em' }}>
            Admin catalog
          </p>
          <h1 style={{ margin: '0.25rem 0 0', fontSize: '2rem' }}>Product catalog</h1>
          <p style={{ margin: '0.5rem 0 0', color: '#555', maxWidth: '40rem' }}>
            Browse the cached catalog instantly. When ERP or PIM changes land, trigger a background sync and continue
            working while shared catalog views catch up shortly after.
          </p>
        </div>

        <form action={syncCatalogAction}>
          <button
            type="submit"
            style={{
              border: 'none',
              borderRadius: '0.75rem',
              padding: '0.85rem 1.1rem',
              background: '#111827',
              color: 'white',
              fontWeight: 600,
              cursor: 'pointer'
            }}
          >
            Sync latest catalog
          </button>
        </form>
      </div>

      <div style={{ marginBottom: '1rem', padding: '1rem', border: '1px solid #e5e7eb', borderRadius: '0.75rem', background: '#f9fafb', color: '#4b5563' }}>
        Sync runs in the background. The current list may stay briefly stale, then refresh across catalog views once the
        shared <code>products</code> cache tag is revalidated.
      </div>

      <div style={{ overflowX: 'auto' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse', minWidth: '720px' }}>
          <thead>
            <tr style={{ textAlign: 'left', borderBottom: '2px solid #e5e7eb' }}>
              <th style={{ padding: '0.75rem' }}>SKU</th>
              <th style={{ padding: '0.75rem' }}>Product</th>
              <th style={{ padding: '0.75rem' }}>Price</th>
              <th style={{ padding: '0.75rem' }}>Inventory</th>
              <th style={{ padding: '0.75rem' }}>Availability</th>
              <th style={{ padding: '0.75rem' }}>Last sync</th>
            </tr>
          </thead>
          <tbody>
            {products.map((product) => (
              <tr key={product.id} style={{ borderBottom: '1px solid #e5e7eb' }}>
                <td style={{ padding: '0.75rem', fontFamily: 'monospace' }}>{product.sku}</td>
                <td style={{ padding: '0.75rem', fontWeight: 600 }}>{product.name}</td>
                <td style={{ padding: '0.75rem' }}>${product.price}</td>
                <td style={{ padding: '0.75rem' }}>{product.inventory}</td>
                <td style={{ padding: '0.75rem' }}>{product.availability}</td>
                <td style={{ padding: '0.75rem', color: '#6b7280' }}>{product.syncedAt ? new Date(product.syncedAt).toLocaleString() : 'Initial snapshot'}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </main>
  );
}
"}

